class InventoryClient:
    BASE_URL = os.environ.get('INVENTORY_URL', 'https://inventory-svc.internal')

    def reserve(self, items):
        url = f'{self.BASE_URL}/api/v1/reserve'
        response = self.session.post(url, json={'items': items}, timeout=5)
        response.raise_for_status()
        return response.json()

    @property
    def session(self):
        if not hasattr(self, '_session'):
            self._session = requests.Session()
            self._session.headers.update({'Authorization': f'Bearer {self._get_token()}'})
        return self._session
```

The session is lazily created per instance, but InventoryClient is instantiated per request in our view. So we're creating a new TLS connection every single request. Is that the root cause?
